import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GoalType {
  SAIR_DO_APERTO = 'A',
  QUITAR_DIVIDAS = 'B',
  COMECAR_RESERVA = 'C',
  INVESTIR = 'D',
  OUTRO = 'E'
}

export interface Debt {
  id: string;
  description: string;
  totalValue: number;
  monthlyInstallment: number;
  interestRate?: number;
  dueDate?: string;
}

export interface FinancialProfile {
  monthlyIncome: number;
  incomeVaries: boolean;
  fixedExpenses: number;
  debts: Debt[];
  currentCash: number;
  mainGoal: GoalType;
  bankContext?: string;
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface ChartData {
  name: string;
  value: number;
  fill?: string;
}

import { GoogleGenAI, Chat, GenerativeModel } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

let aiInstance: GoogleGenAI | null = null;
let chatSession: Chat | null = null;

export const initializeGemini = (apiKey: string) => {
  aiInstance = new GoogleGenAI({ apiKey });
};

export const createChatSession = (): Chat => {
  if (!aiInstance) throw new Error("Gemini not initialized");

  chatSession = aiInstance.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7, // Balanced creativity and precision
    },
  });
  return chatSession;
};

export const sendMessage = async (message: string): Promise<string> => {
  if (!chatSession) {
    createChatSession();
  }

  try {
    const response = await chatSession!.sendMessage({ message });
    return response.text || "Desculpe, não consegui processar sua resposta. Tente novamente.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Ocorreu um erro ao conectar com o assistente. Verifique sua chave de API ou tente novamente mais tarde.";
  }
};

import React from 'react';
import { FinancialProfile, GOAL_LABELS } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis } from 'recharts';

interface Props {
  profile: FinancialProfile;
}

const COLORS = ['#10B981', '#EF4444', '#F59E0B', '#3B82F6'];

const FinancialSummary: React.FC<Props> = ({ profile }) => {
  // Safe formatting for currency
  const formatBRL = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const balance = profile.monthlyIncome - profile.fixedExpenses;
  const debtTotal = profile.debts.reduce((acc, curr) => acc + curr.totalValue, 0);
  const debtMonthly = profile.debts.reduce((acc, curr) => acc + curr.monthlyInstallment, 0);

  const pieData = [
    { name: 'Renda', value: profile.monthlyIncome },
    { name: 'Despesas Fixas', value: profile.fixedExpenses },
    { name: 'Parcelas Dívida', value: debtMonthly },
  ];

  // Filter out zero values for cleaner chart
  const activePieData = pieData.filter(d => d.value > 0);

  return (
    <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 mb-6">
      <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
        <span className="bg-emerald-100 text-emerald-600 p-2 rounded-lg mr-2">📊</span>
        Raio-X Financeiro
      </h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Key Metrics */}
        <div className="space-y-4">
          <div className="p-4 bg-slate-50 rounded-lg">
            <p className="text-sm text-slate-500">Saldo Mensal Estimado</p>
            <p className={`text-2xl font-bold ${balance - debtMonthly >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
              {formatBRL(balance - debtMonthly)}
            </p>
            <p className="text-xs text-slate-400 mt-1">
              (Renda - Fixos - Parcelas)
            </p>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="p-3 bg-red-50 rounded-lg">
                <p className="text-xs text-red-500 font-semibold">Dívida Total</p>
                <p className="text-lg font-bold text-slate-700">{formatBRL(debtTotal)}</p>
             </div>
             <div className="p-3 bg-blue-50 rounded-lg">
                <p className="text-xs text-blue-500 font-semibold">Caixa Disponível</p>
                <p className="text-lg font-bold text-slate-700">{formatBRL(profile.currentCash)}</p>
             </div>
          </div>

          <div className="p-3 border border-dashed border-slate-300 rounded-lg">
             <p className="text-xs text-slate-400 uppercase font-bold tracking-wider">Objetivo Atual</p>
             <p className="text-md font-medium text-slate-700">{GOAL_LABELS[profile.mainGoal]}</p>
          </div>
        </div>

        {/* Charts */}
        <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={activePieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {activePieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatBRL(value)} />
                <Legend verticalAlign="bottom" height={36} iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default FinancialSummary;

import React, { useState } from 'react';
import { FinancialProfile, GoalType, Debt } from '../types';
import { Plus, Trash2, ArrowRight, DollarSign } from 'lucide-react';

interface Props {
  onSubmit: (profile: FinancialProfile) => void;
}

const OnboardingForm: React.FC<Props> = ({ onSubmit }) => {
  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState<FinancialProfile>({
    monthlyIncome: 0,
    incomeVaries: false,
    fixedExpenses: 0,
    debts: [],
    currentCash: 0,
    mainGoal: GoalType.SAIR_DO_APERTO,
    bankContext: ''
  });

  const [currentDebt, setCurrentDebt] = useState<Debt>({
    id: '',
    description: '',
    totalValue: 0,
    monthlyInstallment: 0,
  });

  const handleNext = () => setStep(s => s + 1);
  const handlePrev = () => setStep(s => s - 1);

  const addDebt = () => {
    if (!currentDebt.description || currentDebt.totalValue <= 0) return;
    setProfile(prev => ({
      ...prev,
      debts: [...prev.debts, { ...currentDebt, id: Date.now().toString() }]
    }));
    setCurrentDebt({ id: '', description: '', totalValue: 0, monthlyInstallment: 0 });
  };

  const removeDebt = (id: string) => {
    setProfile(prev => ({
      ...prev,
      debts: prev.debts.filter(d => d.id !== id)
    }));
  };

  const handleSubmit = () => {
    onSubmit(profile);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl p-6 md:p-8 max-w-2xl mx-auto border border-slate-100">
      <div className="mb-6">
        <div className="flex justify-between items-center text-sm font-medium text-slate-400 mb-2">
           <span>Onboarding Financeiro</span>
           <span>Passo {step} de 4</span>
        </div>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
            <div className="bg-emerald-500 h-full transition-all duration-500 ease-out" style={{ width: `${(step / 4) * 100}%` }}></div>
        </div>
      </div>

      {step === 1 && (
        <div className="space-y-6 animate-fade-in">
          <h2 className="text-2xl font-bold text-slate-800">Vamos começar pela sua Renda</h2>
          <p className="text-slate-600">Para te ajudar, preciso saber quanto entra no seu bolso.</p>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Qual sua renda mensal líquida (média)?</label>
            <div className="relative">
              <span className="absolute left-3 top-3 text-slate-400">R$</span>
              <input 
                type="number" 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition"
                placeholder="0.00"
                value={profile.monthlyIncome || ''}
                onChange={e => setProfile({...profile, monthlyIncome: parseFloat(e.target.value)})}
              />
            </div>
          </div>

          <div className="flex items-center space-x-3 bg-slate-50 p-4 rounded-lg">
            <input 
              type="checkbox" 
              id="varies" 
              checked={profile.incomeVaries}
              onChange={e => setProfile({...profile, incomeVaries: e.target.checked})}
              className="w-5 h-5 text-emerald-600 rounded focus:ring-emerald-500"
            />
            <label htmlFor="varies" className="text-slate-700">Minha renda varia mês a mês</label>
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 mb-1">Quanto dinheiro você tem disponível hoje (Caixa)?</label>
             <div className="relative">
              <span className="absolute left-3 top-3 text-slate-400">R$</span>
              <input 
                type="number" 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition"
                placeholder="0.00"
                value={profile.currentCash || ''}
                onChange={e => setProfile({...profile, currentCash: parseFloat(e.target.value)})}
              />
            </div>
          </div>

          <button 
            onClick={handleNext}
            disabled={!profile.monthlyIncome}
            className="w-full bg-slate-900 text-white py-3 rounded-lg font-medium hover:bg-slate-800 disabled:opacity-50 transition flex items-center justify-center gap-2"
          >
            Próximo <ArrowRight size={18} />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-fade-in">
          <h2 className="text-2xl font-bold text-slate-800">Seus Gastos Fixos</h2>
          <p className="text-slate-600">A soma de aluguel, condomínio, luz, internet, escola, etc.</p>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Total de Gastos Fixos Mensais</label>
            <div className="relative">
              <span className="absolute left-3 top-3 text-slate-400">R$</span>
              <input 
                type="number" 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition"
                placeholder="0.00"
                value={profile.fixedExpenses || ''}
                onChange={e => setProfile({...profile, fixedExpenses: parseFloat(e.target.value)})}
              />
            </div>
            <p className="text-xs text-slate-500 mt-2">Não precisa ser exato, uma estimativa próxima já ajuda.</p>
          </div>

          <div className="flex gap-3">
            <button onClick={handlePrev} className="flex-1 py-3 border border-slate-300 rounded-lg font-medium hover:bg-slate-50 transition">Voltar</button>
            <button onClick={handleNext} className="flex-1 bg-slate-900 text-white py-3 rounded-lg font-medium hover:bg-slate-800 transition">Próximo</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6 animate-fade-in">
          <h2 className="text-2xl font-bold text-slate-800">Dívidas</h2>
          <p className="text-slate-600">Liste cartões, empréstimos ou financiamentos (se tiver).</p>

          <div className="bg-slate-50 p-4 rounded-xl space-y-3 border border-slate-200">
            <input 
              type="text" 
              placeholder="Nome (ex: Cartão Nubank)" 
              className="w-full px-3 py-2 border rounded-md"
              value={currentDebt.description}
              onChange={e => setCurrentDebt({...currentDebt, description: e.target.value})}
            />
            <div className="grid grid-cols-2 gap-3">
              <input 
                type="number" 
                placeholder="Valor Total (R$)" 
                className="w-full px-3 py-2 border rounded-md"
                value={currentDebt.totalValue || ''}
                onChange={e => setCurrentDebt({...currentDebt, totalValue: parseFloat(e.target.value)})}
              />
              <input 
                type="number" 
                placeholder="Parcela Mensal (R$)" 
                className="w-full px-3 py-2 border rounded-md"
                value={currentDebt.monthlyInstallment || ''}
                onChange={e => setCurrentDebt({...currentDebt, monthlyInstallment: parseFloat(e.target.value)})}
              />
            </div>
            <button 
              onClick={addDebt}
              className="w-full py-2 bg-emerald-600 text-white rounded-md font-medium text-sm hover:bg-emerald-700 flex items-center justify-center gap-2"
            >
              <Plus size={16} /> Adicionar Dívida
            </button>
          </div>

          {profile.debts.length > 0 && (
            <div className="space-y-2 max-h-40 overflow-y-auto">
               {profile.debts.map(debt => (
                 <div key={debt.id} className="flex justify-between items-center bg-white border border-slate-200 p-3 rounded-lg">
                    <div>
                      <p className="font-medium text-slate-800">{debt.description}</p>
                      <p className="text-xs text-slate-500">Total: R$ {debt.totalValue} | Parc: R$ {debt.monthlyInstallment}</p>
                    </div>
                    <button onClick={() => removeDebt(debt.id)} className="text-red-400 hover:text-red-600 p-2">
                      <Trash2 size={16} />
                    </button>
                 </div>
               ))}
            </div>
          )}

          <div className="flex gap-3">
            <button onClick={handlePrev} className="flex-1 py-3 border border-slate-300 rounded-lg font-medium hover:bg-slate-50 transition">Voltar</button>
            <button onClick={handleNext} className="flex-1 bg-slate-900 text-white py-3 rounded-lg font-medium hover:bg-slate-800 transition">Próximo</button>
          </div>
        </div>
      )}

      {step === 4 && (
        <div className="space-y-6 animate-fade-in">
          <h2 className="text-2xl font-bold text-slate-800">Objetivo & Contexto</h2>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Qual seu foco principal nos próximos 3 meses?</label>
            <div className="grid grid-cols-1 gap-2">
              {[
                { val: GoalType.SAIR_DO_APERTO, label: 'Sair do aperto (Conta fechando no vermelho)' },
                { val: GoalType.QUITAR_DIVIDAS, label: 'Quitar dívidas (Limpar o nome/parar juros)' },
                { val: GoalType.COMECAR_RESERVA, label: 'Começar reserva de emergência' },
                { val: GoalType.INVESTIR, label: 'Investir para crescer' },
                { val: GoalType.OUTRO, label: 'Outro' },
              ].map((opt) => (
                <button
                  key={opt.val}
                  onClick={() => setProfile({...profile, mainGoal: opt.val})}
                  className={`text-left px-4 py-3 rounded-lg border transition ${
                    profile.mainGoal === opt.val 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800 ring-1 ring-emerald-500' 
                      : 'border-slate-200 hover:bg-slate-50'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 mb-1">Bancos ou cartões principais (Opcional)</label>
             <input 
                type="text" 
                className="w-full px-4 py-3 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-emerald-500"
                placeholder="Ex: Nubank, Itaú, XP..."
                value={profile.bankContext}
                onChange={e => setProfile({...profile, bankContext: e.target.value})}
              />
          </div>

          <div className="flex gap-3 pt-4">
            <button onClick={handlePrev} className="flex-1 py-3 border border-slate-300 rounded-lg font-medium hover:bg-slate-50 transition">Voltar</button>
            <button 
              onClick={handleSubmit} 
              className="flex-1 bg-emerald-600 text-white py-3 rounded-lg font-bold hover:bg-emerald-700 transition shadow-lg shadow-emerald-200"
            >
              Gerar Diagnóstico
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default OnboardingForm;

import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { Send, User, Bot, Loader2 } from 'lucide-react';

interface Props {
  messages: Message[];
  onSendMessage: (text: string) => void;
  isLoading: boolean;
}

const ChatInterface: React.FC<Props> = ({ messages, onSendMessage, isLoading }) => {
  const [input, setInput] = useState('');
  const endOfMessagesRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    endOfMessagesRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    onSendMessage(input);
    setInput('');
  };

  const formatText = (text: string) => {
    // Basic formatting for the AI response to handle headers and lists clearly
    return text.split('\n').map((line, i) => {
      if (line.trim().startsWith('📌') || line.trim().startsWith('🚨') || line.trim().startsWith('🕳️') || line.trim().startsWith('🎯') || line.trim().startsWith('✅')) {
         return <p key={i} className="font-bold text-slate-900 mt-4 mb-2">{line}</p>;
      }
      if (line.trim().startsWith('- ')) {
         return <li key={i} className="ml-4 list-disc text-slate-700 mb-1">{line.substring(2)}</li>;
      }
      if (line.trim() === '') {
        return <br key={i}/>;
      }
      return <p key={i} className="mb-2 text-slate-700 leading-relaxed">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 scrollbar-hide">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`flex max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} items-start gap-2`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-emerald-600 text-white'
              }`}>
                {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
              </div>

              <div className={`p-4 rounded-2xl text-sm ${
                msg.role === 'user' 
                  ? 'bg-slate-800 text-white rounded-tr-none' 
                  : 'bg-white border border-slate-200 shadow-sm rounded-tl-none'
              }`}>
                <div className={msg.role === 'model' ? 'prose-sm' : ''}>
                  {msg.role === 'model' ? formatText(msg.text) : msg.text}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
           <div className="flex justify-start w-full">
             <div className="flex flex-row items-center gap-2 max-w-[75%]">
                <div className="w-8 h-8 rounded-full bg-emerald-600 text-white flex items-center justify-center">
                   <Bot size={16} />
                </div>
                <div className="bg-white border border-slate-200 p-4 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-2">
                   <Loader2 className="animate-spin text-emerald-600" size={18} />
                   <span className="text-slate-500 text-sm">Analisando suas finanças...</span>
                </div>
             </div>
           </div>
        )}
        <div ref={endOfMessagesRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Digite sua resposta..."
            className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:bg-white transition"
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className="bg-emerald-600 text-white p-3 rounded-xl hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition shadow-md shadow-emerald-100"
          >
            <Send size={20} />
          </button>
        </div>
      </form>
    </div>
  );
};

export default ChatInterface;

