import React, { useState, useEffect } from 'react';
import OnboardingForm from './components/OnboardingForm';
import ChatInterface from './components/ChatInterface';
import FinancialSummary from './components/FinancialSummary';
import { FinancialProfile, Message } from './types';
import { initializeGemini, sendMessage } from './services/geminiService';
import { PieChart } from 'lucide-react';

function App() {
  const [hasProfile, setHasProfile] = useState(false);
  const [profile, setProfile] = useState<FinancialProfile | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [view, setView] = useState<'chat' | 'dashboard'>('chat');

  useEffect(() => {
    // Initialize Gemini with the ENV key as per strict instructions
    // Note: In a real Vite/WebPack build, this needs VITE_API_KEY or REACT_APP_API_KEY mapped to process.env.API_KEY
    const apiKey = process.env.API_KEY || '';
    if (apiKey) {
      initializeGemini(apiKey);
    } else {
      // Fallback for demo purposes if environment variable is missing in the runtime container
      console.warn("API Key missing from environment variables.");
    }
  }, []);

  const handleOnboardingSubmit = async (data: FinancialProfile) => {
    setProfile(data);
    setHasProfile(true);
    setIsLoading(true);

    // Construct the initial prompt based on the form data
    const debtDetails = data.debts.map(d => 
      `- ${d.description}: R$${d.totalValue} total, parcela de R$${d.monthlyInstallment}`
    ).join('\n');

    const prompt = `
