import React, { useState } from 'react';
import { Transaction } from '../types';
import { ArrowDownCircle, ArrowUpCircle, Plus, Trash2 } from 'lucide-react';

interface Props {
  transactions: Transaction[];
  onAddTransaction: (t: Transaction) => void;
  onRemoveTransaction: (id: string) => void;
}

const TransactionsTab: React.FC<Props> = ({ transactions, onAddTransaction, onRemoveTransaction }) => {
  const [newTrans, setNewTrans] = useState<Partial<Transaction>>({
    description: '',
    value: 0,
    type: 'expense',
    category: 'Alimentação'
  });

  const handleAdd = () => {
    if (!newTrans.description || !newTrans.value) return;
    onAddTransaction({
      id: Date.now().toString(),
      description: newTrans.description,
      value: Number(newTrans.value),
      type: newTrans.type as 'income' | 'expense',
      category: newTrans.category || 'Geral',
      date: new Date().toISOString()
    });
    setNewTrans({ ...newTrans, description: '', value: 0 });
  };

  // Calculate totals from the ledger only
  const totalIncome = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.value, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.value, 0);
  const balance = totalIncome - totalExpense;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-3 gap-3">
        <div className="bg-emerald-50 p-3 rounded-xl border border-emerald-100">
          <p className="text-xs text-emerald-600 font-medium">Receitas</p>
          <p className="text-lg font-bold text-emerald-700">R$ {totalIncome.toLocaleString('pt-BR')}</p>
        </div>
        <div className="bg-red-50 p-3 rounded-xl border border-red-100">
          <p className="text-xs text-red-600 font-medium">Despesas</p>
          <p className="text-lg font-bold text-red-700">R$ {totalExpense.toLocaleString('pt-BR')}</p>
        </div>
        <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
          <p className="text-xs text-slate-500 font-medium">Saldo (Mês)</p>
          <p className={`text-lg font-bold ${balance >= 0 ? 'text-slate-700' : 'text-red-600'}`}>
            R$ {balance.toLocaleString('pt-BR')}
          </p>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-sm font-semibold text-slate-700 mb-3">Novo Lançamento</h3>
        <div className="flex flex-col gap-3">
          <div className="flex gap-2">
            <button 
              onClick={() => setNewTrans({...newTrans, type: 'expense'})}
              className={`flex-1 py-2 text-sm rounded-lg font-medium transition ${newTrans.type === 'expense' ? 'bg-red-100 text-red-700 ring-1 ring-red-300' : 'bg-slate-50 text-slate-500'}`}
            >
              Despesa
            </button>
            <button 
              onClick={() => setNewTrans({...newTrans, type: 'income'})}
              className={`flex-1 py-2 text-sm rounded-lg font-medium transition ${newTrans.type === 'income' ? 'bg-emerald-100 text-emerald-700 ring-1 ring-emerald-300' : 'bg-slate-50 text-slate-500'}`}
            >
              Receita
            </button>
          </div>
          <input 
            type="text" 
            placeholder="Descrição (ex: Supermercado)"
            className="w-full p-2 border border-slate-200 rounded-lg text-sm"
            value={newTrans.description}
            onChange={e => setNewTrans({...newTrans, description: e.target.value})}
          />
          <div className="flex gap-2">
            <input 
              type="number" 
              placeholder="Valor"
              className="flex-1 p-2 border border-slate-200 rounded-lg text-sm"
              value={newTrans.value || ''}
              onChange={e => setNewTrans({...newTrans, value: parseFloat(e.target.value)})}
            />
            <button 
              onClick={handleAdd}
              className="bg-slate-900 text-white px-4 rounded-lg hover:bg-slate-800 transition"
            >
              <Plus size={20} />
            </button>
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h3 className="text-sm font-semibold text-slate-500 pl-1">Histórico Recente</h3>
        {transactions.slice().reverse().map(t => (
          <div key={t.id} className="flex justify-between items-center bg-white p-3 rounded-lg border border-slate-100">
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-full ${t.type === 'income' ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                {t.type === 'income' ? <ArrowUpCircle size={18} /> : <ArrowDownCircle size={18} />}
              </div>
              <div>
                <p className="text-sm font-medium text-slate-800">{t.description}</p>
                <p className="text-xs text-slate-400">{new Date(t.date).toLocaleDateString('pt-BR')}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <span className={`font-semibold text-sm ${t.type === 'income' ? 'text-emerald-600' : 'text-red-600'}`}>
                {t.type === 'income' ? '+' : '-'} R$ {t.value.toLocaleString('pt-BR')}
              </span>
              <button onClick={() => onRemoveTransaction(t.id)} className="text-slate-300 hover:text-red-400">
                <Trash2 size={14} />
              </button>
            </div>
          </div>
        ))}
        {transactions.length === 0 && (
          <p className="text-center text-slate-400 text-xs py-4">Nenhum lançamento ainda.</p>
        )}
      </div>
    </div>
  );
};

