import React, { useState, useEffect } from 'react';
import OnboardingForm from './components/OnboardingForm';
import ChatInterface from './components/ChatInterface';
import FinancialSummary from './components/FinancialSummary';
import GoalsTab from './components/GoalsTab';
import TransactionsTab from './components/TransactionsTab';
import { FinancialProfile, Message, FinancialGoal, Transaction, GoalType } from './types';
import { initializeGemini, sendMessage } from './services/geminiService';
import { PieChart, MessageSquare, LayoutDashboard, Target, Receipt } from 'lucide-react';

function App() {
  const [hasProfile, setHasProfile] = useState(false);
  const [profile, setProfile] = useState<FinancialProfile | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'dashboard' | 'goals' | 'transactions'>('chat');

  // New State for tabs
  const [goals, setGoals] = useState<FinancialGoal[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  useEffect(() => {
    const apiKey = process.env.API_KEY || '';
    if (apiKey) {
      initializeGemini(apiKey);
    } else {
      console.warn("API Key missing from environment variables.");
    }
  }, []);

  const handleOnboardingSubmit = async (data: FinancialProfile) => {
    setProfile(data);
    setHasProfile(true);
    setIsLoading(true);

    // Initialize a default goal based on selection
    const defaultGoalMap: Record<string, string> = {
      [GoalType.SAIR_DO_APERTO]: "Reserva de Sobrevivência",
      [GoalType.QUITAR_DIVIDAS]: "Quitação de Dívidas",
      [GoalType.COMECAR_RESERVA]: "Reserva de Emergência",
      [GoalType.INVESTIR]: "Primeiro Milhão",
      [GoalType.OUTRO]: "Meta Personalizada"
    };

    setGoals([{
      id: 'default-1',
      title: defaultGoalMap[data.mainGoal] || 'Minha Meta',
      currentAmount: data.currentCash, // Assume current cash counts towards initial goal
      targetAmount: data.monthlyIncome * 6, // Generic rule of thumb
      deadline: ''
    }]);

    const debtDetails = data.debts.map(d => 
      `- ${d.description}: R$${d.totalValue} total, parcela de R$${d.monthlyInstallment}`
    ).join('\n');

    const prompt = `
Aqui estão meus dados iniciais para o diagnóstico:

1. Renda Líquida Mensal: R$ ${data.monthlyIncome} ${data.incomeVaries ? '(Varia)' : '(Fixa)'}
2. Gastos Fixos Totais: R$ ${data.fixedExpenses}
3. Caixa Atual (Disponível): R$ ${data.currentCash}
4. Objetivo Principal: ${data.mainGoal}
5. Contexto Bancário: ${data.bankContext || 'Não informado'}
6. Dívidas:
${debtDetails || 'Nenhuma dívida declarada.'}

Por favor, gere o DIAGNÓSTICO conforme seu formato padrão.
    `;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: "Enviei meus dados financeiros. Aguardando diagnóstico.",
      timestamp: new Date()
    };
    setMessages([userMsg]);

    try {
      const response = await sendMessage(prompt);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendMessage = async (text: string) => {
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const response = await sendMessage(text);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
       // Error handled
    } finally {
      setIsLoading(false);
    }
  };

  // State handlers
  const addGoal = (g: FinancialGoal) => setGoals([...goals, g]);
  const removeGoal = (id: string) => setGoals(goals.filter(g => g.id !== id));
  const updateGoal = (g: FinancialGoal) => setGoals(goals.map(goal => goal.id === g.id ? g : goal));

  const addTransaction = (t: Transaction) => setTransactions([...transactions, t]);
  const removeTransaction = (id: string) => setTransactions(transactions.filter(t => t.id !== id));

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center pb-20 md:pb-0">
      {/* Header - Simplified */}
      <header className="w-full bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-4xl mx-auto px-4 py-3 flex justify-between items-center">
