import { GoogleGenAI, Chat, FunctionDeclaration, SchemaType, Type } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';

let aiInstance: GoogleGenAI | null = null;
let chatSession: Chat | null = null;

// Definition for the Add Transaction Tool
const addTransactionTool: FunctionDeclaration = {
  name: 'addTransaction',
  description: 'Adiciona uma nova transação financeira (receita ou despesa) ao registro do usuário.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      type: {
        type: Type.STRING,
        enum: ['income', 'expense'],
        description: 'Tipo da transação: "income" para receitas/ganhos, "expense" para gastos/despesas.',
      },
      description: {
        type: Type.STRING,
        description: 'Descrição curta da transação (ex: Almoço, Uber, Salário).',
      },
      value: {
        type: Type.NUMBER,
        description: 'Valor numérico da transação.',
      },
      category: {
        type: Type.STRING,
        description: 'Categoria da transação (ex: Alimentação, Transporte, Lazer, Moradia, Salário).',
      },
    },
    required: ['type', 'description', 'value'],
  },
};

// Definition for Add Goal Tool
const addGoalTool: FunctionDeclaration = {
  name: 'addGoal',
  description: 'Cria uma nova meta financeira ou objetivo de poupança.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      title: {
        type: Type.STRING,
        description: 'Título da meta (ex: Viagem, Carro Novo, Reserva).',
      },
      targetAmount: {
        type: Type.NUMBER,
        description: 'Valor total que se deseja alcançar.',
      },
      deadline: {
        type: Type.STRING,
        description: 'Data limite opcional (YYYY-MM-DD) se mencionada.',
      }
    },
    required: ['title', 'targetAmount'],
  },
};


export const initializeGemini = (apiKey: string) => {
  aiInstance = new GoogleGenAI({ apiKey });
};

export const createChatSession = (): Chat => {
  if (!aiInstance) throw new Error("Gemini not initialized");

  // Using gemini-2.5-flash-preview for better tool use and speed
  chatSession = aiInstance.chats.create({
    model: 'gemini-2.5-flash-preview', 
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.7,
      tools: [{ functionDeclarations: [addTransactionTool, addGoalTool] }],
    },
  });
  return chatSession;
};

// Now returns an object that might contain text AND/OR function calls
export const sendMessage = async (messageText: string, audioBase64?: string) => {
  if (!chatSession) {
    createChatSession();
  }

  try {
    let result;

    if (audioBase64) {
      // If audio is provided, send it as a part
      result = await chatSession!.sendMessage({
        content: {
          parts: [
            { inlineData: { mimeType: 'audio/webm;codecs=opus', data: audioBase64 } }, // Standard browser recorder mime
            { text: messageText || "Transcreva este áudio e execute qualquer comando financeiro nele, ou responda à pergunta." }
          ]
        }
      });
    } else {
      result = await chatSession!.sendMessage({ message: messageText });
    }

    // Extract text
    const text = result.text;

    // Extract function calls if any
    const functionCalls = result.candidates?.[0]?.content?.parts
      ?.filter(part => part.functionCall)
      .map(part => part.functionCall);

    return {
      text,
      functionCalls
    };

  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Erro ao conectar com a IA. Tente novamente." };
  }
};

// Helper to send tool response back to model (confirmation)
export const sendToolResponse = async (functionName: string, id: string, result: any) => {
  if (!chatSession) return;

  const response = await chatSession.sendMessage({
    content: {
      role: 'function',
      parts: [{
        functionResponse: {
          name: functionName,
          response: { result: result },
          id: id
        }
      }]
    }
  });

  return response.text;
};

import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { Send, User, Bot, Loader2, Mic, StopCircle, ArrowDownCircle, ArrowUpCircle, Target, TrendingUp, DollarSign } from 'lucide-react';

interface Props {
  messages: Message[];
  onSendMessage: (text: string, audioBase64?: string) => void;
  isLoading: boolean;
}

const ChatInterface: React.FC<Props> = ({ messages, onSendMessage, isLoading }) => {
  const [input, setInput] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const endOfMessagesRef = useRef<HTMLDivElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    endOfMessagesRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    onSendMessage(input);
    setInput('');
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' }); 
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
           const base64String = (reader.result as string).split(',')[1];
           onSendMessage('', base64String);
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Erro ao acessar microfone. Verifique as permissões.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleQuickAction = (action: string) => {
    if (action === 'Gasto') setInput('Adicionar gasto de R$ ');
    if (action === 'Receita') setInput('Adicionar receita de R$ ');
    if (action === 'Meta') setInput('Nova meta: ');
    if (action === 'Resumo') onSendMessage('Faça um resumo da minha situação atual.');
  };

  const formatText = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.trim().startsWith('📌') || line.trim().startsWith('🚨') || line.trim().startsWith('🕳️') || line.trim().startsWith('🎯') || line.trim().startsWith('✅')) {
         return <p key={i} className="font-bold text-slate-900 mt-4 mb-2">{line}</p>;
      }
      if (line.trim().startsWith('- ')) {
         return <li key={i} className="ml-4 list-disc text-slate-700 mb-1">{line.substring(2)}</li>;
      }
      if (line.trim() === '') {
        return <br key={i}/>;
      }
      return <p key={i} className="mb-2 text-slate-700 leading-relaxed">{line}</p>;
    });
  };

  const renderActionCard = (msg: Message) => {
    if (!msg.actionData) return null;

    if (msg.actionData.type === 'transaction_added') {
      const t = msg.actionData.data;
      const isExpense = t.type === 'expense';
      return (
        <div className="mt-3 bg-white border border-slate-200 rounded-xl p-3 shadow-sm flex items-center gap-3 w-fit">
          <div className={`p-2 rounded-full ${isExpense ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
            {isExpense ? <ArrowDownCircle size={20} /> : <ArrowUpCircle size={20} />}
          </div>
          <div>
            <p className="text-xs text-slate-400 font-medium uppercase">{isExpense ? 'Despesa Registrada' : 'Receita Registrada'}</p>
            <p className="font-bold text-slate-800">{t.description}</p>
            <p className={`font-mono font-medium ${isExpense ? 'text-red-600' : 'text-emerald-600'}`}>
              R$ {t.value.toLocaleString('pt-BR')}
            </p>
          </div>
        </div>
      );
    }

    if (msg.actionData.type === 'goal_added') {
      const g = msg.actionData.data;
      return (
        <div className="mt-3 bg-white border border-slate-200 rounded-xl p-3 shadow-sm flex items-center gap-3 w-fit">
          <div className="p-2 rounded-full bg-blue-100 text-blue-600">
            <Target size={20} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-medium uppercase">Nova Meta Criada</p>
            <p className="font-bold text-slate-800">{g.title}</p>
            <p className="text-sm text-slate-600">Alvo: R$ {g.targetAmount.toLocaleString('pt-BR')}</p>
          </div>
        </div>
      );
    }

    return null;
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 scrollbar-hide">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`flex flex-col max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div className={`flex items-start gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                  msg.role === 'user' ? 'bg-slate-800 text-white' : 'bg-emerald-600 text-white'
                }`}>
                  {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                </div>

                <div className={`p-4 rounded-2xl text-sm ${
                  msg.role === 'user' 
                    ? 'bg-slate-800 text-white rounded-tr-none' 
                    : 'bg-white border border-slate-200 shadow-sm rounded-tl-none'
                }`}>
                  <div className={msg.role === 'model' ? 'prose-sm' : ''}>
                    {msg.isAudio ? (
                      <div className="flex items-center gap-2 italic text-slate-300">
                        <Mic size={14} /> Áudio enviado
                      </div>
                    ) : (
                      msg.role === 'model' ? formatText(msg.text) : msg.text
                    )}
                  </div>
                </div>
              </div>
              {/* Render Action Card underneath the text bubble */}
              {renderActionCard(msg)}
            </div>
          </div>
        ))}
        {isLoading && (
           <div className="flex justify-start w-full">
             <div className="flex flex-row items-center gap-2 max-w-[75%]">
                <div className="w-8 h-8 rounded-full bg-emerald-600 text-white flex items-center justify-center">
                   <Bot size={16} />
                </div>
                <div className="bg-white border border-slate-200 p-4 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-2">
                   <Loader2 className="animate-spin text-emerald-600" size={18} />
                   <span className="text-slate-500 text-sm">
                     {isRecording ? "Processando áudio..." : "Analisando..."}
                   </span>
                </div>
             </div>
           </div>
        )}
        <div ref={endOfMessagesRef} />
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        {/* Quick Actions */}
        <div className="flex gap-2 mb-3 overflow-x-auto pb-1 scrollbar-hide">
          <button onClick={() => handleQuickAction('Gasto')} className="flex items-center gap-1 px-3 py-1.5 bg-red-50 text-red-600 rounded-lg text-xs font-medium hover:bg-red-100 border border-red-100 whitespace-nowrap">
            <ArrowDownCircle size={14} /> Adicionar Gasto
          </button>
          <button onClick={() => handleQuickAction('Receita')} className="flex items-center gap-1 px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-lg text-xs font-medium hover:bg-emerald-100 border border-emerald-100 whitespace-nowrap">
             <ArrowUpCircle size={14} /> Adicionar Receita
          </button>
           <button onClick={() => handleQuickAction('Meta')} className="flex items-center gap-1 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-lg text-xs font-medium hover:bg-blue-100 border border-blue-100 whitespace-nowrap">
             <Target size={14} /> Criar Meta
          </button>
           <button onClick={() => handleQuickAction('Resumo')} className="flex items-center gap-1 px-3 py-1.5 bg-slate-50 text-slate-600 rounded-lg text-xs font-medium hover:bg-slate-100 border border-slate-200 whitespace-nowrap">
             <DollarSign size={14} /> Resumo
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex gap-2">
          {/* Mic Button */}
          <button
            type="button"
            onMouseDown={startRecording}
            onMouseUp={stopRecording}
            onTouchStart={startRecording}
            onTouchEnd={stopRecording}
            disabled={isLoading}
            className={`p-3 rounded-xl transition shadow-sm flex-shrink-0 ${
              isRecording 
                ? 'bg-red-500 text-white animate-pulse' 
                : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
            }`}
            title="Segure para gravar"
          >
            {isRecording ? <StopCircle size={20} /> : <Mic size={20} />}
          </button>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={isRecording ? "Gravando..." : "Digite ou fale..."}
            className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:bg-white transition min-w-0"
            disabled={isLoading || isRecording}
          />
          <button
            type="submit"
            disabled={isLoading || isRecording || !input.trim()}
            className="bg-emerald-600 text-white p-3 rounded-xl hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition shadow-md shadow-emerald-100 flex-shrink-0"
          >
            <Send size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect } from 'react';
import OnboardingForm from './components/OnboardingForm';
import ChatInterface from './components/ChatInterface';
import FinancialSummary from './components/FinancialSummary';
import GoalsTab from './components/GoalsTab';
import TransactionsTab from './components/TransactionsTab';
import { FinancialProfile, Message, FinancialGoal, Transaction, GoalType } from './types';
import { initializeGemini, sendMessage, sendToolResponse } from './services/geminiService';
import { PieChart, MessageSquare, LayoutDashboard, Target, Receipt } from 'lucide-react';

function App() {
  const [hasProfile, setHasProfile] = useState(false);
  const [profile, setProfile] = useState<FinancialProfile | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'dashboard' | 'goals' | 'transactions'>('chat');

  // State for tabs
  const [goals, setGoals] = useState<FinancialGoal[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  useEffect(() => {
    const apiKey = process.env.API_KEY || '';
    if (apiKey) {
      initializeGemini(apiKey);
    } else {
      console.warn("API Key missing from environment variables.");
    }
  }, []);

  // TOOL HANDLERS
  const handleAddTransactionTool = (args: any): Transaction => {
    const newTrans: Transaction = {
      id: Date.now().toString(),
      type: args.type === 'expense' ? 'expense' : 'income',
      description: args.description,
      value: args.value,
      category: args.category || 'Geral',
      date: new Date().toISOString()
    };
    setTransactions(prev => [...prev, newTrans]);
    return newTrans;
  };

  const handleAddGoalTool = (args: any): FinancialGoal => {
    const newGoal: FinancialGoal = {
      id: Date.now().toString(),
      title: args.title,
      targetAmount: args.targetAmount,
      currentAmount: 0,
      deadline: args.deadline || ''
    };
    setGoals(prev => [...prev, newGoal]);
    return newGoal;
  };

  const handleOnboardingSubmit = async (data: FinancialProfile) => {
    setProfile(data);
    setHasProfile(true);
    setIsLoading(true);

    // Dynamic Goals initialization based on specific path
    const defaultGoals: FinancialGoal[] = [];

    if (data.mainGoal === GoalType.SAIR_DO_VERMELHO) {
       defaultGoals.push({
         id: '1', title: 'Quitar Dívidas Menores', currentAmount: 0, targetAmount: 2000, deadline: ''
       });
    } else if (data.mainGoal === GoalType.INVESTIR_BOLSA) {
       defaultGoals.push({
         id: '1', title: 'Aporte Inicial', currentAmount: data.currentCash, targetAmount: 50000, deadline: ''
       });
    } else if (data.mainGoal === GoalType.INVESTIR_NEGOCIO) {
       defaultGoals.push({
         id: '1', title: 'Capital de Giro', currentAmount: data.currentCash, targetAmount: 10000, deadline: ''
       });
    } else {
       defaultGoals.push({
         id: '1', title: 'Reserva de Emergência', currentAmount: data.currentCash, targetAmount: data.monthlyIncome * 6, deadline: ''
       });
    }

    setGoals(defaultGoals);

    const debtDetails = data.debts.map(d => 
      `- ${d.description}: R$${d.totalValue} total, parcela de R$${d.monthlyInstallment}`
    ).join('\n');

    const prompt = `
Aqui estão meus dados iniciais para o diagnóstico:

1. Objetivo Principal: ${data.mainGoal} (Considere isso como prioridade absoluta)
2. Renda Líquida Mensal: R$ ${data.monthlyIncome} ${data.incomeVaries ? '(Varia)' : '(Fixa)'}
3. Gastos Fixos Totais: R$ ${data.fixedExpenses}
4. Caixa Atual (Disponível): R$ ${data.currentCash}
5. Contexto Bancário: ${data.bankContext || 'Não informado'}
6. Dívidas:
${debtDetails || 'Nenhuma dívida declarada.'}

Por favor, gere o DIAGNÓSTICO focado no meu objetivo principal (${data.mainGoal}).
    `;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: "Enviei meus dados financeiros. Aguardando diagnóstico.",
      timestamp: new Date()
    };
    setMessages([userMsg]);

    try {
      const { text } = await sendMessage(prompt);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text || "Olá! Recebi seus dados.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendMessage = async (text: string, audioBase64?: string) => {
    // Add user message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: text || (audioBase64 ? "Mensagem de áudio enviada" : ""),
      isAudio: !!audioBase64,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 1. Send Message (Text or Audio)
      const { text: responseText, functionCalls } = await sendMessage(text, audioBase64);

      let finalResponseText = responseText;
      let actionData: any = null;

      // 2. Handle Tool Calls
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {

          if (call.name === 'addTransaction') {
             const newTrans = handleAddTransactionTool(call.args);
             actionData = { type: 'transaction_added', data: newTrans };

             // Inform Model
             const confirmation = await sendToolResponse(call.name, call.id, { result: "Success" });
             if (confirmation) finalResponseText = confirmation;
             else finalResponseText = "Certo, já registrei.";
          }

          if (call.name === 'addGoal') {
             const newGoal = handleAddGoalTool(call.args);
             actionData = { type: 'goal_added', data: newGoal };

             const confirmation = await sendToolResponse(call.name, call.id, { result: "Success" });
             if (confirmation) finalResponseText = confirmation;
             else finalResponseText = "Meta criada com sucesso!";
          }
        }
      }

      // 3. Add Bot Message
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: finalResponseText || "Entendido.",
        timestamp: new Date(),
        actionData: actionData
      };
      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
       console.error(error);
       setMessages(prev => [...prev, {
         id: Date.now().toString(),
         role: 'model',
         text: "Desculpe, tive um problema ao processar. Tente novamente.",
         timestamp: new Date()
       }]);
    } finally {
      setIsLoading(false);
    }
  };

  // State handlers
  const addGoal = (g: FinancialGoal) => setGoals([...goals, g]);
  const removeGoal = (id: string) => setGoals(goals.filter(g => g.id !== id));
  const updateGoal = (g: FinancialGoal) => setGoals(goals.map(goal => goal.id === g.id ? g : goal));

  const addTransaction = (t: Transaction) => setTransactions([...transactions, t]);
  const removeTransaction = (id: string) => setTransactions(transactions.filter(t => t.id !== id));

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center pb-20 md:pb-0">
      {/* Header - Simplified */}
      <header className="w-full bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-4xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="bg-emerald-600 text-white p-2 rounded-lg">
              <PieChart size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none">CFO Pessoal</h1>
              <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wide">Brasil</p>
            </div>
          </div>
          {/* Desktop Navigation */}
          {hasProfile && (
            <nav className="hidden md:flex gap-1 bg-slate-100 p-1 rounded-lg">
              <button onClick={() => setActiveTab('chat')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'chat' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Chat</button>
              <button onClick={() => setActiveTab('dashboard')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'dashboard' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Dashboard</button>
              <button onClick={() => setActiveTab('goals')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'goals' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Metas</button>
              <button onClick={() => setActiveTab('transactions')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'transactions' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Lançamentos</button>
            </nav>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full max-w-4xl px-4 py-6 flex-1">
        {!hasProfile ? (
          <div className="mt-8">
            <OnboardingForm onSubmit={handleOnboardingSubmit} />
          </div>
        ) : (
          <div className="animate-fade-in">
            <div className={activeTab === 'chat' ? 'block' : 'hidden'}>
               <ChatInterface messages={messages} onSendMessage={handleSendMessage} isLoading={isLoading} />
            </div>

            {activeTab === 'dashboard' && profile && (
              <div className="space-y-6">
                 <FinancialSummary profile={profile} />
                 <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl">
                    <p className="text-sm text-emerald-800 font-medium">Dica do CFO:</p>
                    <p className="text-sm text-emerald-700 mt-1">
                      Você pode usar o microfone no Chat para dizer "Gastei 20 reais na padaria" e eu registro automaticamente em <strong>Lançamentos</strong>.
                    </p>
                 </div>
              </div>
            )}

            {activeTab === 'goals' && (
              <GoalsTab goals={goals} onAddGoal={addGoal} onRemoveGoal={removeGoal} onUpdateGoal={updateGoal} />
            )}

            {activeTab === 'transactions' && (
              <TransactionsTab transactions={transactions} onAddTransaction={addTransaction} onRemoveTransaction={removeTransaction} />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Navigation */}
      {hasProfile && (
        <div className="md:hidden fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 py-2 px-6 flex justify-between items-center z-30 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
           <button onClick={() => setActiveTab('chat')} className={`flex flex-col items-center gap-1 ${activeTab === 'chat' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <MessageSquare size={20} strokeWidth={activeTab === 'chat' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Chat</span>
           </button>
           <button onClick={() => setActiveTab('dashboard')} className={`flex flex-col items-center gap-1 ${activeTab === 'dashboard' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <LayoutDashboard size={20} strokeWidth={activeTab === 'dashboard' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Resumo</span>
           </button>
           <button onClick={() => setActiveTab('goals')} className={`flex flex-col items-center gap-1 ${activeTab === 'goals' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <Target size={20} strokeWidth={activeTab === 'goals' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Metas</span>
           </button>
           <button onClick={() => setActiveTab('transactions')} className={`flex flex-col items-center gap-1 ${activeTab === 'transactions' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <Receipt size={20} strokeWidth={activeTab === 'transactions' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Lançar</span>
           </button>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { FinancialProfile, GoalType, Debt } from '../types';
import { Plus, Trash2, ArrowRight, TrendingUp, ShieldAlert, PieChart, Briefcase, X } from 'lucide-react';

interface Props {
  onSubmit: (profile: FinancialProfile) => void;
  onSkip: () => void;
}

const OnboardingForm: React.FC<Props> = ({ onSubmit, onSkip }) => {
  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState<FinancialProfile>({
    monthlyIncome: 0,
    incomeVaries: false,
    fixedExpenses: 0,
    debts: [],
    currentCash: 0,
    mainGoal: GoalType.ORGANIZACAO, // Default
    bankContext: ''
  });

  const [currentDebt, setCurrentDebt] = useState<Debt>({
    id: '',
    description: '',
    totalValue: 0,
    monthlyInstallment: 0,
  });

  const handleNext = () => setStep(s => s + 1);
  const handlePrev = () => setStep(s => s - 1);

  const addDebt = () => {
    if (!currentDebt.description || currentDebt.totalValue <= 0) return;
    setProfile(prev => ({
      ...prev,
      debts: [...prev.debts, { ...currentDebt, id: Date.now().toString() }]
    }));
    setCurrentDebt({ id: '', description: '', totalValue: 0, monthlyInstallment: 0 });
  };

  const removeDebt = (id: string) => {
    setProfile(prev => ({
      ...prev,
      debts: prev.debts.filter(d => d.id !== id)
    }));
  };

  const handleSubmit = () => {
    onSubmit(profile);
  };

  // Helper to render Goal Cards
  const GoalCard = ({ type, icon: Icon, title, desc }: any) => (
    <button
      onClick={() => {
        setProfile({...profile, mainGoal: type});
        setTimeout(handleNext, 150); // Auto advance slightly
      }}
      className={`text-left w-full p-4 rounded-xl border-2 transition-all duration-200 flex items-start gap-4 hover:shadow-md ${
        profile.mainGoal === type 
          ? 'border-emerald-500 bg-emerald-50 ring-1 ring-emerald-500' 
          : 'border-slate-100 bg-white hover:border-emerald-200'
      }`}
    >
      <div className={`p-3 rounded-lg ${profile.mainGoal === type ? 'bg-emerald-200 text-emerald-800' : 'bg-slate-100 text-slate-500'}`}>
        <Icon size={24} />
      </div>
      <div>
        <h3 className={`font-bold ${profile.mainGoal === type ? 'text-emerald-900' : 'text-slate-800'}`}>{title}</h3>
        <p className="text-sm text-slate-500 mt-1 leading-snug">{desc}</p>
      </div>
    </button>
  );

  return (
    <div className="bg-white rounded-2xl shadow-xl p-6 md:p-8 max-w-2xl mx-auto border border-slate-100 relative">
      {/* Skip Button */}
      <button 
        onClick={onSkip}
        className="absolute top-6 right-6 text-slate-400 hover:text-slate-600 text-sm font-medium flex items-center gap-1 transition"
      >
        Pular Configuração <X size={16} />
      </button>

      <div className="mb-6 pr-20">
        <div className="flex justify-between items-center text-sm font-medium text-slate-400 mb-2">
           <span>Diagnóstico Inicial</span>
           <span>Passo {step} de 4</span>
        </div>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
