import React, { useState } from 'react';
import { Transaction, Debt } from '../types';
import { Edit2, Trash2, Check, X, Plus, Table as TableIcon } from 'lucide-react';

interface Props {
  transactions: Transaction[];
  debts: Debt[];
  onUpdateTransaction: (t: Transaction) => void;
  onDeleteTransaction: (id: string) => void;
  onAddTransaction: (t: Transaction) => void;
  onUpdateDebt: (d: Debt) => void;
  onDeleteDebt: (id: string) => void;
  onAddDebt: (d: Debt) => void;
}

const SheetsTab: React.FC<Props> = ({ 
  transactions, debts, 
  onUpdateTransaction, onDeleteTransaction, onAddTransaction,
  onUpdateDebt, onDeleteDebt, onAddDebt
}) => {
  const [activeTable, setActiveTable] = useState<'transactions' | 'debts'>('transactions');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempRow, setTempRow] = useState<any>(null);

  // --- Helpers ---
  const handleEdit = (item: any) => {
    setEditingId(item.id);
    setTempRow({ ...item });
  };

  const handleCancel = () => {
    setEditingId(null);
    setTempRow(null);
  };

  const handleDelete = (id: string, type: 't' | 'd') => {
    if (confirm('Tem certeza que deseja excluir esta linha?')) {
      if (type === 't') onDeleteTransaction(id);
      else onDeleteDebt(id);
    }
  };

  const handleSave = (type: 't' | 'd') => {
    if (type === 't') {
       // Convert tags string to array if needed (simplified for input)
       const finalTrans = { ...tempRow };
       if (typeof finalTrans.tags === 'string') {
          finalTrans.tags = finalTrans.tags.split(',').map((s: string) => s.trim());
       }
       // If it's a new item (we handle "add" logic differently usually, but here likely update or add)
       onUpdateTransaction(finalTrans);
    } else {
       const finalDebt = { ...tempRow };
        if (typeof finalDebt.tags === 'string') {
          finalDebt.tags = finalDebt.tags.split(',').map((s: string) => s.trim());
       }
       onUpdateDebt(finalDebt);
    }
    setEditingId(null);
    setTempRow(null);
  };

  const handleAddNew = () => {
    const newId = Date.now().toString();
    if (activeTable === 'transactions') {
      const newT: Transaction = {
        id: newId,
        date: new Date().toISOString().split('T')[0],
        type: 'expense',
        value: 0,
        category: 'Geral',
        description: 'Nova Transação',
        tags: []
      };
      onAddTransaction(newT);
      handleEdit(newT); // Enter edit mode immediately
    } else {
      const newD: Debt = {
        id: newId,
        description: 'Nova Dívida',
        totalValue: 0,
        monthlyInstallment: 0,
        debtType: 'card',
        dueDate: '1',
        tags: []
      };
      onAddDebt(newD);
      handleEdit(newD);
    }
  };

  const handleChange = (field: string, value: any) => {
    setTempRow((prev: any) => ({ ...prev, [field]: value }));
  };

  // --- Renderers ---

  const renderTransactionTable = () => (
    <div className="overflow-x-auto rounded-lg border border-slate-200">
      <table className="w-full text-sm text-left text-slate-600">
        <thead className="text-xs text-slate-700 uppercase bg-slate-100">
          <tr>
            <th className="px-4 py-3">Data</th>
            <th className="px-4 py-3">Tipo</th>
            <th className="px-4 py-3">Valor (R$)</th>
            <th className="px-4 py-3">Categoria</th>
            <th className="px-4 py-3">Descrição</th>
            <th className="px-4 py-3">Tags</th>
            <th className="px-4 py-3 text-right">Ações</th>
          </tr>
        </thead>
        <tbody>
          {transactions.slice().reverse().map(t => {
            const isEditing = editingId === t.id;
            const data = isEditing ? tempRow : t;

            return (
              <tr key={t.id} className="bg-white border-b hover:bg-slate-50">
                <td className="px-4 py-3">
                  {isEditing ? (
                    <input type="date" value={data.date.split('T')[0]} onChange={e => handleChange('date', e.target.value)} className="w-full border rounded p-1" />
                  ) : new Date(t.date).toLocaleDateString('pt-BR')}
                </td>
                <td className="px-4 py-3">
                  {isEditing ? (
                     <select value={data.type} onChange={e => handleChange('type', e.target.value)} className="w-full border rounded p-1">
                        <option value="expense">Despesa</option>
                        <option value="income">Receita</option>
                     </select>
                  ) : (
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${t.type === 'income' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                      {t.type === 'income' ? 'Receita' : 'Despesa'}
                    </span>
                  )}
                </td>
                <td className="px-4 py-3 font-medium text-slate-900">
                  {isEditing ? (
                    <input type="number" value={data.value} onChange={e => handleChange('value', parseFloat(e.target.value))} className="w-24 border rounded p-1" />
                  ) : t.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <input type="text" value={data.category} onChange={e => handleChange('category', e.target.value)} className="w-full border rounded p-1" />
                   ) : t.category}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <input type="text" value={data.description} onChange={e => handleChange('description', e.target.value)} className="w-full border rounded p-1" />
                   ) : t.description}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <input type="text" placeholder="sep. por vírgula" value={Array.isArray(data.tags) ? data.tags.join(', ') : data.tags} onChange={e => handleChange('tags', e.target.value)} className="w-full border rounded p-1" />
                   ) : (t.tags?.join(', ') || '-')}
                </td>
                <td className="px-4 py-3 text-right">
                  {isEditing ? (
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleSave('t')} className="text-emerald-600 hover:bg-emerald-50 p-1 rounded"><Check size={16} /></button>
                      <button onClick={handleCancel} className="text-red-500 hover:bg-red-50 p-1 rounded"><X size={16} /></button>
                    </div>
                  ) : (
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleEdit(t)} className="text-slate-400 hover:text-blue-600 p-1"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(t.id, 't')} className="text-slate-400 hover:text-red-600 p-1"><Trash2 size={16} /></button>
                    </div>
                  )}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );

  const renderDebtsTable = () => (
    <div className="overflow-x-auto rounded-lg border border-slate-200">
      <table className="w-full text-sm text-left text-slate-600">
        <thead className="text-xs text-slate-700 uppercase bg-slate-100">
          <tr>
            <th className="px-4 py-3">Nome</th>
            <th className="px-4 py-3">Tipo</th>
            <th className="px-4 py-3">Saldo Total</th>
            <th className="px-4 py-3">Parcela</th>
            <th className="px-4 py-3">Dia Venc.</th>
            <th className="px-4 py-3">Tags</th>
            <th className="px-4 py-3 text-right">Ações</th>
          </tr>
        </thead>
        <tbody>
          {debts.map(d => {
            const isEditing = editingId === d.id;
            const data = isEditing ? tempRow : d;

            return (
              <tr key={d.id} className="bg-white border-b hover:bg-slate-50">
                <td className="px-4 py-3 font-medium text-slate-900">
                  {isEditing ? (
                     <input type="text" value={data.description} onChange={e => handleChange('description', e.target.value)} className="w-full border rounded p-1" />
                   ) : d.description}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <select value={data.debtType || 'other'} onChange={e => handleChange('debtType', e.target.value)} className="w-full border rounded p-1">
                        <option value="card">Cartão</option>
                        <option value="loan">Empréstimo</option>
                        <option value="overdraft">Cheque Esp.</option>
                        <option value="other">Outros</option>
                     </select>
                   ) : (
                     d.debtType === 'card' ? 'Cartão' : d.debtType === 'loan' ? 'Empréstimo' : d.debtType === 'overdraft' ? 'Cheque Esp.' : 'Outros'
                   )}
                </td>
                <td className="px-4 py-3">
                  {isEditing ? (
                    <input type="number" value={data.totalValue} onChange={e => handleChange('totalValue', parseFloat(e.target.value))} className="w-24 border rounded p-1" />
                  ) : d.totalValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                    <input type="number" value={data.monthlyInstallment} onChange={e => handleChange('monthlyInstallment', parseFloat(e.target.value))} className="w-24 border rounded p-1" />
                  ) : d.monthlyInstallment.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <input type="text" value={data.dueDate || ''} onChange={e => handleChange('dueDate', e.target.value)} className="w-16 border rounded p-1" />
                   ) : d.dueDate || '-'}
                </td>
                <td className="px-4 py-3">
                   {isEditing ? (
                     <input type="text" placeholder="tags" value={Array.isArray(data.tags) ? data.tags.join(', ') : data.tags} onChange={e => handleChange('tags', e.target.value)} className="w-full border rounded p-1" />
                   ) : (d.tags?.join(', ') || '-')}
                </td>
                <td className="px-4 py-3 text-right">
                  {isEditing ? (
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleSave('d')} className="text-emerald-600 hover:bg-emerald-50 p-1 rounded"><Check size={16} /></button>
                      <button onClick={handleCancel} className="text-red-500 hover:bg-red-50 p-1 rounded"><X size={16} /></button>
                    </div>
                  ) : (
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleEdit(d)} className="text-slate-400 hover:text-blue-600 p-1"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(d.id, 'd')} className="text-slate-400 hover:text-red-600 p-1"><Trash2 size={16} /></button>
                    </div>
                  )}
                </td>
              </tr>
            );
          })}
          {debts.length === 0 && (
            <tr>
              <td colSpan={7} className="text-center py-8 text-slate-400">Nenhuma dívida registrada.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );

  return (
    <div className="space-y-6 pb-20">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
         <div className="flex bg-slate-100 p-1 rounded-lg">
            <button 
              onClick={() => setActiveTable('transactions')}
              className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTable === 'transactions' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Transações
            </button>
            <button 
              onClick={() => setActiveTable('debts')}
              className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTable === 'debts' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Dívidas
            </button>
         </div>

         <button 
           onClick={handleAddNew}
           className="bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-emerald-700 transition"
         >
           <Plus size={16} /> Adicionar {activeTable === 'transactions' ? 'Linha' : 'Dívida'}
         </button>
      </div>

      {/* Main Grid */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200">
         {activeTable === 'transactions' ? renderTransactionTable() : renderDebtsTable()}
      </div>
    </div>
  );
};

export default SheetsTab;

import React, { useState, useEffect } from 'react';
import OnboardingForm from './components/OnboardingForm';
import ChatInterface from './components/ChatInterface';
import DashboardTab from './components/DashboardTab';
import GoalsTab from './components/GoalsTab';
import TransactionsTab from './components/TransactionsTab';
import SheetsTab from './components/SheetsTab';
import { FinancialProfile, Message, FinancialGoal, Transaction, GoalType, Debt } from './types';
import { initializeGemini, sendMessage, sendToolResponse } from './services/geminiService';
import { PieChart, MessageSquare, LayoutDashboard, Target, Receipt, Table } from 'lucide-react';

function App() {
  const [hasProfile, setHasProfile] = useState(false);
  const [profile, setProfile] = useState<FinancialProfile | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'dashboard' | 'goals' | 'transactions' | 'sheets'>('chat');

  // State for tabs
  const [goals, setGoals] = useState<FinancialGoal[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  useEffect(() => {
    const apiKey = process.env.API_KEY || '';
    if (apiKey) {
      initializeGemini(apiKey);
    } else {
      console.warn("API Key missing from environment variables.");
    }
  }, []);

  // TOOL HANDLERS
  const handleAddTransactionTool = (args: any): Transaction => {
    const newTrans: Transaction = {
      id: Date.now().toString(),
      type: args.type === 'expense' ? 'expense' : 'income',
      description: args.description,
      value: args.value,
      category: args.category || 'Geral',
      date: new Date().toISOString()
    };
    setTransactions(prev => [...prev, newTrans]);
    return newTrans;
  };

  const handleAddGoalTool = (args: any): FinancialGoal => {
    const newGoal: FinancialGoal = {
      id: Date.now().toString(),
      title: args.title,
      targetAmount: args.targetAmount,
      currentAmount: 0,
      deadline: args.deadline || ''
    };
    setGoals(prev => [...prev, newGoal]);
    return newGoal;
  };

  // Skip Handler - Create "Guest" Profile
  const handleSkipOnboarding = () => {
    const guestProfile: FinancialProfile = {
      monthlyIncome: 0,
      incomeVaries: false,
      fixedExpenses: 0,
      debts: [],
      currentCash: 0,
      mainGoal: GoalType.ORGANIZACAO,
      bankContext: 'Não informado'
    };
    setProfile(guestProfile);
    setHasProfile(true);

    // Add a welcome message encouraging setup via chat
    const welcomeMsg: Message = {
      id: 'welcome',
      role: 'model',
      text: "Bem-vindo ao modo rápido! Como pulei a configuração, seus dados estão zerados. Você pode me dizer 'Ganho 5000 por mês' ou 'Gastei 50 no almoço' para começar a alimentar o sistema.",
      timestamp: new Date()
    };
    setMessages([welcomeMsg]);
  };

  const handleOnboardingSubmit = async (data: FinancialProfile) => {
    setProfile(data);
    setHasProfile(true);
    setIsLoading(true);

    // Dynamic Goals initialization based on specific path
    const defaultGoals: FinancialGoal[] = [];

    if (data.mainGoal === GoalType.SAIR_DO_VERMELHO) {
       defaultGoals.push({
         id: '1', title: 'Quitar Dívidas Menores', currentAmount: 0, targetAmount: 2000, deadline: ''
       });
    } else if (data.mainGoal === GoalType.INVESTIR_BOLSA) {
       defaultGoals.push({
         id: '1', title: 'Aporte Inicial', currentAmount: data.currentCash, targetAmount: 50000, deadline: ''
       });
    } else if (data.mainGoal === GoalType.INVESTIR_NEGOCIO) {
       defaultGoals.push({
         id: '1', title: 'Capital de Giro', currentAmount: data.currentCash, targetAmount: 10000, deadline: ''
       });
    } else {
       defaultGoals.push({
         id: '1', title: 'Reserva de Emergência', currentAmount: data.currentCash, targetAmount: data.monthlyIncome * 6, deadline: ''
       });
    }

    setGoals(defaultGoals);

    const debtDetails = data.debts.map(d => 
      `- ${d.description}: R$${d.totalValue} total, parcela de R$${d.monthlyInstallment}`
    ).join('\n');

    const prompt = `
Aqui estão meus dados iniciais para o diagnóstico:

1. Objetivo Principal: ${data.mainGoal} (Considere isso como prioridade absoluta)
2. Renda Líquida Mensal: R$ ${data.monthlyIncome} ${data.incomeVaries ? '(Varia)' : '(Fixa)'}
3. Gastos Fixos Totais: R$ ${data.fixedExpenses}
4. Caixa Atual (Disponível): R$ ${data.currentCash}
5. Contexto Bancário: ${data.bankContext || 'Não informado'}
6. Dívidas:
${debtDetails || 'Nenhuma dívida declarada.'}

Por favor, gere o DIAGNÓSTICO focado no meu objetivo principal (${data.mainGoal}).
    `;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: "Enviei meus dados financeiros. Aguardando diagnóstico.",
      timestamp: new Date()
    };
    setMessages([userMsg]);

    try {
      const { text } = await sendMessage(prompt);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text || "Olá! Recebi seus dados.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendMessage = async (text: string, audioBase64?: string) => {
    // Add user message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: text || (audioBase64 ? "Mensagem de áudio enviada" : ""),
      isAudio: !!audioBase64,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 1. Send Message (Text or Audio)
      const { text: responseText, functionCalls } = await sendMessage(text, audioBase64);

      let finalResponseText = responseText;
      let actionData: any = null;

      // 2. Handle Tool Calls
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {

          if (call.name === 'addTransaction') {
             const newTrans = handleAddTransactionTool(call.args);
             actionData = { type: 'transaction_added', data: newTrans };

             // Inform Model
             const confirmation = await sendToolResponse(call.name, call.id, { result: "Success" });
             if (confirmation) finalResponseText = confirmation;
             else finalResponseText = "Certo, já registrei.";
          }

          if (call.name === 'addGoal') {
             const newGoal = handleAddGoalTool(call.args);
             actionData = { type: 'goal_added', data: newGoal };

             const confirmation = await sendToolResponse(call.name, call.id, { result: "Success" });
             if (confirmation) finalResponseText = confirmation;
             else finalResponseText = "Meta criada com sucesso!";
          }
        }
      }

      // 3. Add Bot Message
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: finalResponseText || "Entendido.",
        timestamp: new Date(),
        actionData: actionData
      };
      setMessages(prev => [...prev, botMsg]);

    } catch (error) {
       console.error(error);
       setMessages(prev => [...prev, {
         id: Date.now().toString(),
         role: 'model',
         text: "Desculpe, tive um problema ao processar. Tente novamente.",
         timestamp: new Date()
       }]);
    } finally {
      setIsLoading(false);
    }
  };

  // State handlers
  const addGoal = (g: FinancialGoal) => setGoals([...goals, g]);
  const removeGoal = (id: string) => setGoals(goals.filter(g => g.id !== id));
  const updateGoal = (g: FinancialGoal) => setGoals(goals.map(goal => goal.id === g.id ? g : goal));

  const addTransaction = (t: Transaction) => setTransactions([...transactions, t]);
  const updateTransaction = (t: Transaction) => setTransactions(transactions.map(tr => tr.id === t.id ? t : tr));
  const removeTransaction = (id: string) => setTransactions(transactions.filter(t => t.id !== id));

  // Debt Handlers (Profile Context)
  const addDebt = (d: Debt) => {
    if (!profile) return;
    setProfile({ ...profile, debts: [...profile.debts, d] });
  };
  const updateDebt = (d: Debt) => {
    if (!profile) return;
    setProfile({ ...profile, debts: profile.debts.map(debt => debt.id === d.id ? d : debt) });
  };
  const removeDebt = (id: string) => {
    if (!profile) return;
    setProfile({ ...profile, debts: profile.debts.filter(d => d.id !== id) });
  };


  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center pb-20 md:pb-0">
      {/* Header - Simplified */}
      <header className="w-full bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-4xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="bg-emerald-600 text-white p-2 rounded-lg">
              <PieChart size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none">CFO Pessoal</h1>
              <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wide">Brasil</p>
            </div>
          </div>
          {/* Desktop Navigation */}
          {hasProfile && (
            <nav className="hidden md:flex gap-1 bg-slate-100 p-1 rounded-lg">
              <button onClick={() => setActiveTab('chat')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'chat' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Chat</button>
              <button onClick={() => setActiveTab('dashboard')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'dashboard' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Dashboard</button>
              <button onClick={() => setActiveTab('goals')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'goals' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Metas</button>
              <button onClick={() => setActiveTab('transactions')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'transactions' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Lançamentos</button>
              <button onClick={() => setActiveTab('sheets')} className={`px-4 py-2 text-sm font-medium rounded-md transition ${activeTab === 'sheets' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}>Planilhas</button>
            </nav>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full max-w-4xl px-4 py-6 flex-1">
        {!hasProfile ? (
          <div className="mt-8">
            <OnboardingForm onSubmit={handleOnboardingSubmit} onSkip={handleSkipOnboarding} />
          </div>
        ) : (
          <div className="animate-fade-in">
            <div className={activeTab === 'chat' ? 'block' : 'hidden'}>
               <ChatInterface messages={messages} onSendMessage={handleSendMessage} isLoading={isLoading} />
            </div>

            {activeTab === 'dashboard' && profile && (
              <DashboardTab profile={profile} transactions={transactions} />
            )}

            {activeTab === 'goals' && (
              <GoalsTab goals={goals} onAddGoal={addGoal} onRemoveGoal={removeGoal} onUpdateGoal={updateGoal} />
            )}

            {activeTab === 'transactions' && (
              <TransactionsTab transactions={transactions} onAddTransaction={addTransaction} onRemoveTransaction={removeTransaction} />
            )}

            {activeTab === 'sheets' && profile && (
              <SheetsTab 
                transactions={transactions} 
                debts={profile.debts}
                onAddTransaction={addTransaction}
                onUpdateTransaction={updateTransaction}
                onDeleteTransaction={removeTransaction}
                onAddDebt={addDebt}
                onUpdateDebt={updateDebt}
                onDeleteDebt={removeDebt}
              />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Navigation */}
      {hasProfile && (
        <div className="md:hidden fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 py-2 px-6 flex justify-between items-center z-30 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
           <button onClick={() => setActiveTab('chat')} className={`flex flex-col items-center gap-1 ${activeTab === 'chat' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <MessageSquare size={20} strokeWidth={activeTab === 'chat' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Chat</span>
           </button>
           <button onClick={() => setActiveTab('dashboard')} className={`flex flex-col items-center gap-1 ${activeTab === 'dashboard' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <LayoutDashboard size={20} strokeWidth={activeTab === 'dashboard' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Resumo</span>
           </button>
           <button onClick={() => setActiveTab('transactions')} className={`flex flex-col items-center gap-1 ${activeTab === 'transactions' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <Receipt size={20} strokeWidth={activeTab === 'transactions' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Lançar</span>
           </button>
           <button onClick={() => setActiveTab('sheets')} className={`flex flex-col items-center gap-1 ${activeTab === 'sheets' ? 'text-emerald-600' : 'text-slate-400'}`}>
              <Table size={20} strokeWidth={activeTab === 'sheets' ? 2.5 : 2} />
              <span className="text-[10px] font-medium">Planilhas</span>
           </button>
        </div>
      )}
    </div>
  );
}

export default App;
